(window.webpackJsonp=window.webpackJsonp||[]).push([[167],{794:function(r,n){r.exports='\x3c!-- \r\ntitle: 05-NexT个性化\r\nsort: \r\n--\x3e \r\n# NexT主题个性化配置\r\n\r\n## 配置\r\n\r\n- 更改主题配置文件\r\n\r\n  > NexT共有三种主题设定\r\n  >\r\n  > \\#scheme: Muse \r\n  >\r\n  > #scheme: Mist \r\n  >\r\n  > #scheme: Pisces\r\n\r\n  ```bash\r\n  notepad themes/next/_config.yml\r\n  # 设置菜单栏对应中文\r\n  # 在language目录下对应的语言文件\r\n  ```\r\n\r\n- 设定菜单内容\r\n\r\n  | 键值       | 设定值                    | 显示文本 |\r\n  | :--------- | :------------------------ | :------- |\r\n  | home       | `home: /`                 | 主页     |\r\n  | archives   | `archives: /archives`     | 归档页   |\r\n  | categories | `categories: /categories` | 分类页   |\r\n  | tags       | `tags: /tags`             | 标签页   |\r\n  | about      | `about: /about`           | 关于页面 |\r\n  | commonweal | `commonweal: /404.html`   | 404      |\r\n\r\n- 创建菜单文件\r\n\r\n  ```bash\r\n  hexo n page tags\r\n  # 打开index.md\r\n  # 添加Font-Matter:\r\n  #\ttitle: 标签\r\n  #\ttype: "tags"\r\n  hexo n page categories\r\n  #\ttype: "categories"\r\n  ```\r\n\r\n- 设定头像\r\n\r\n  ```bash\r\n  avatar: URL/PATH\r\n  ```\r\n\r\n- 侧边栏社交链接\r\n\r\n  ```bash\r\n  social:\r\n  \t#名称: 链接\r\n  ```\r\n\r\n- 设定菜单显示文本\r\n\r\n  > 在language目录下对应的语言文件\r\n\r\n- 添加友链\r\n\r\n  > 编辑NexT_config：`link`字段\r\n\r\n- 开启打赏\r\n\r\n  > 修改`reward_settings`为`true`\r\n  >\r\n  > 在`reward`中添加二维码\r\n\r\n- 其他发布平台\r\n\r\n  > `follow_me`\r\n\r\n- 设置头像\r\n\r\n  > `\\themes\\next\\source\\css\\_common\\outline\\sidebar\\sidebar-author.styl`\r\n  >\r\n  > ```css\r\n  > border-radius: 20%;\t/*头像变圆*/\r\n  > ```\r\n\r\n- 设置阅读全文\r\n\r\n  > 在文章中添加\r\n  >\r\n  > `\x3c!--more--\x3e`\r\n\r\n- 添加动态背景\r\n\r\n  > ```bash\r\n  > cd themes/next\r\n  > git clone https://github.com/theme-next/theme-next-three source/lib/three\r\n  > ```\r\n  >\r\n  > 开启动态背景\r\n  >\r\n  > ```css\r\n  > three:\r\n  > enable: true\r\n  > three_waves: true\r\n  > canvas_lines: false\r\n  > canvas_sphere: false\r\n  > ```\r\n\r\n\r\n## 编辑文章\r\n\r\n- 新建文章\r\n\r\n  > `hexo n firstblog`\r\n  >\r\n  > 保存在_posts文件夹\r\n  >\r\n  > 修改md文件添加信息\r\n\r\n- 修改内链颜色\r\n\r\n  > `.\\themes\\next\\source\\css\\_common\\components\\post\\post.styl`\r\n  >\r\n  > ```css\r\n  > .post-body p a {\r\n  > color: #345;\r\n  > border-bottom: none;\r\n  > &:hover{\r\n  >  color:#aaa;\r\n  > }\r\n  > }\r\n  > ```\r\n\r\n- 修改图标\r\n\r\n  > `".\\themes\\next\\layout\\_macro\\post.swig"`\r\n  >\r\n  > https://fontawesome.com/\r\n  >\r\n  > ```css\r\n  > rel="tag" \r\n  > /* 在此之后添加 */\r\n  > <i class="fas fa-tags"></i>\r\n  > ```\r\n\r\n## 添加功能\r\n\r\n- 评论功能：https://leancloud.cn/\r\n\r\n  ```yml\r\n  # _config.yml\r\n  valine:\r\n    enable: false\r\n  ```\r\n\r\n- Local Search\r\n\r\n  添加百度/谷歌/本地 自定义站点内容搜索\r\n\r\n  1. 安装 `hexo-generator-searchdb`，在站点的根目录下执行以下命令：\r\n\r\n     ```bash\r\n     $ npm install hexo-generator-searchdb --save\r\n     ```\r\n\r\n  2. 编辑 **站点配置文件**，新增以下内容到任意位置：\r\n\r\n     ```yml\r\n     search:\r\n       path: search.xml\r\n       field: post\r\n       format: html\r\n       limit: 10000\r\n     ```\r\n\r\n  3. 编辑 **主题配置文件**，启用本地搜索功能：\r\n\r\n     ```yml\r\n     # Local search\r\n     local_search:\r\n       enable: true\r\n     ```'}}]);